// --- Importanções
import React, { useState } from 'react';
import "./SubmitionBar.css"

// --- Função SubmitionBar
const SubmitionBar = ( { children, handleAddition, type = "text" } ) => {
    const [inputData, setInputData] = useState("");

    const handleInputChange = (aux) => {
        setInputData(aux.target.value);
    };

    const handleAddClick = () => {
        if (inputData.trim()) {
            handleAddition(inputData);
        }
    };

    const handleKeyPress = (pressKey) => {
        if (pressKey.key === 'Enter') {
            handleAddClick
        }
    }

    return (
        <div className = "add-container">
            <input
                onChange={handleInputChange}
                onKeyPress={handleKeyPress}
                value = {inputData}
                className = "add-input"
                type={type}
                placeholder={children}
            />
        </div>
    );
};

export default SubmitionBar;

